-- Swedish, French and Arabic versions of the initial CIVICAVITA editorial posts.
-- Run after migrations 0001–0006.
INSERT OR REPLACE INTO posts (id,title,excerpt,content,category,author,author_role,date,cover_emoji,cover_image,read_minutes,tags,locale,translation_key) VALUES
('sv-editorial-evidence-field','Från yrkeserfarenhet till offentlig evidens: en omsorgsfull början','CIVICAVITA inleder sitt offentliga arbete genom att tydligt skilja dokumenterad yrkeserfarenhet från påståenden om en organisation.','CIVICAVITA AB utvecklar sin offentliga forsknings- och rådgivningsverksamhet från Sverige. Utgångspunkten är inte ett anspråk på redan genomförda storskaliga program, utan ett åtagande att använda evidens omsorgsfullt, beskriva arbetets omfattning tydligt och utveckla verksamheten stegvis.\n\nDr. Sahar Motallebi har dokumenterad yrkeserfarenhet inom folkhälsa och humanitära sammanhang, bland annat roller inom ministerier, WHO, UNICEF, UNDP och UN Women. Erfarenheterna formar verksamhetens perspektiv, men innebär inte att dessa organisationer är nuvarande CIVICAVITA-partner.\n\nDenna skillnad är viktig. Inom global hälsa bygger trovärdighet på tydlig attribuering, relevant evidens och respekt för människor och institutioner som står nära frågan.','Redaktionellt','CIVICAVITA AB','Redaktionellt team','2026-07-21','🔎','/images/insight-evidence-health.jpg',2,'["Evidens","Transparens","Global hälsa"]','sv','evidence-field'),
('sv-editorial-displacement-health','Fördrivning, boende och hälsa: frågor som kräver långsiktig uppmärksamhet','Reflektioner utifrån dokumenterat arbete om hälsans sociala bestämningsfaktorer för fördrivna grupper och boende efter katastrofer.','Tillfälligt boende är aldrig bara en logistisk fråga. Det påverkar integritet, säkerhet, exponering för väder, vårdens kontinuitet och de sociala villkor som formar hälsa.\n\nDr. Sahar Motallebi har i sin akademiska och yrkesmässiga dokumentation arbete om hälsans sociala bestämningsfaktorer för fördrivna befolkningar samt en konferenspresentation från 2006 om halvpermanent boende efter katastrofer. Erfarenheterna väcker en bestående fråga: vad händer när ett kortsiktigt svar blir ett långsiktigt levnadsvillkor?\n\nCIVICAVITA kommer att utforska frågan genom noggrann evidenssyntes och offentliga texter, utan att presentera tidigare arbete som ett pågående program.','Humanitär vetenskap','CIVICAVITA AB','Redaktionellt team','2026-07-18','⛺','/images/insight-humanitarian-research.jpg',2,'["Fördrivning","Boende","Hälsojämlikhet"]','sv','displacement-health'),
('sv-editorial-health-systems','Motståndskraftiga hälsosystem byggs genom kontinuitet, lärande och tillit','Hälsosystemens resiliens är inte ett teknikpåstående utan ett långsiktigt arbete med institutioner, data, människor och tillgång till vård.','Hälsosystem möter samtidiga påfrestningar som kroniska sjukdomar, klimatrisker, fördrivning, personalbrist och ojämlik tillgång till information. Resiliens är inte en produkt som kan installeras. Det är en kapacitet som byggs genom kontinuitet i vården, lokal kunskap, lärande och ansvarsfulla institutioner.\n\nGrundarens dokumenterade erfarenhet omfattar tekniskt arbete med policy för icke-smittsamma sjukdomar, uppföljning och utvärdering, katastrofplanering och hälsoprogram. CIVICAVITA använder dessa erfarenhetsområden för att formulera forsknings- och rådgivningsfrågor.\n\nVårt offentliga skrivande fokuserar på användbara frågor, tydlig evidens och praktiska begränsningar, inte på löften om omvandling.','Hälsosystem','CIVICAVITA AB','Redaktionellt team','2026-07-15','🏥','/images/insight-health-systems.jpg',2,'["Hälsosystem","Resiliens","Policy"]','sv','health-systems'),
('sv-editorial-responsible-ai','Ansvarsfull AI börjar med ansvarstagande mänskligt omdöme','AI kan stödja forskning och kommunikation, men kan inte ersätta kontextkunskap, etisk granskning eller ansvar.','AI kan hjälpa till att organisera information, skapa strukturerade första utkast och stödja kunskapsflöden. Inom folkhälsa och humanitära sammanhang är ett välformulerat svar dock inte nödvändigtvis ett tillförlitligt svar.\n\nCIVICAVITA ser AI som stödjande teknik. Källor måste kontrolleras, osäkerhet måste uttryckas och personer med relevant kontextkunskap är fortsatt ansvariga för besluten. Detta är särskilt viktigt när data är ofullständiga, situationer förändras snabbt eller konsekvenserna av fel är allvarliga.\n\nCIVICAVITA utforskar ansvarsfulla AI-metoder med omsorg och publicerar endast arbete som har lämplig mänsklig granskning.','Ansvarsfull AI','CIVICAVITA AB','Redaktionellt team','2026-07-12','🧠','/images/insight-responsible-ai.jpg',2,'["Ansvarsfull AI","Etik","Forskning"]','sv','responsible-ai'),
('fr-editorial-evidence-field','De l’expérience professionnelle aux preuves publiques : un départ rigoureux','CIVICAVITA commence son travail public en distinguant clairement l’expérience professionnelle documentée des affirmations sur une organisation.','CIVICAVITA AB développe depuis la Suède son activité publique de recherche et de conseil. Son point de départ n’est pas de prétendre avoir déjà mené des programmes à grande échelle, mais de s’engager à utiliser les preuves avec rigueur, à préciser le périmètre de son travail et à développer son activité progressivement.\n\nLa Dre Sahar Motallebi possède une expérience professionnelle documentée en santé publique et dans des contextes humanitaires, notamment au sein de ministères, de l’OMS, de l’UNICEF, du PNUD et d’ONU Femmes. Ces expériences éclairent la perspective de la structure, sans faire de ces organisations des partenaires actuels de CIVICAVITA.\n\nCette distinction est importante. En santé mondiale, la crédibilité dépend d’une attribution transparente, de preuves appropriées et du respect des personnes et institutions les plus proches de chaque enjeu.','Éditorial','CIVICAVITA AB','Équipe éditoriale','2026-07-21','🔎','/images/insight-evidence-health.jpg',2,'["Preuves","Transparence","Santé mondiale"]','fr','evidence-field'),
('fr-editorial-displacement-health','Déplacement, abri et santé : des questions qui exigent une attention durable','Réflexions fondées sur des travaux documentés concernant les déterminants sociaux de la santé des populations déplacées et l’abri après les catastrophes.','Un abri temporaire n’est jamais une simple question logistique. Il affecte l’intimité, la sécurité, l’exposition aux conditions climatiques, la continuité des soins et les conditions sociales qui influencent la santé.\n\nLe parcours universitaire et professionnel documenté de la Dre Sahar Motallebi comprend des travaux sur les déterminants sociaux de la santé des populations déplacées et une présentation de 2006 sur l’abri semi-permanent après catastrophe. Ces expériences posent une question durable : que se passe-t-il lorsqu’une réponse à court terme devient une condition de vie à long terme ?\n\nCIVICAVITA explorera ce sujet par des synthèses rigoureuses et des notes publiques, sans présenter des travaux antérieurs comme un programme actuel.','Science humanitaire','CIVICAVITA AB','Équipe éditoriale','2026-07-18','⛺','/images/insight-humanitarian-research.jpg',2,'["Déplacement","Abri","Équité en santé"]','fr','displacement-health'),
('fr-editorial-health-systems','Des systèmes de santé résilients se construisent par la continuité, l’apprentissage et la confiance','La résilience des systèmes de santé n’est pas une promesse technologique : elle exige un travail durable sur les institutions, les données, les personnes et l’accès aux soins.','Les systèmes de santé font face à des pressions simultanées : maladies chroniques, risques climatiques, déplacements, pénuries de personnel et accès inégal à l’information. La résilience n’est pas un produit que l’on installe. C’est une capacité construite par la continuité des soins, les savoirs locaux, l’apprentissage et des institutions responsables.\n\nLe parcours documenté de la fondatrice inclut un travail technique sur les politiques relatives aux maladies non transmissibles, le suivi et l’évaluation, la planification des catastrophes et les programmes de santé. CIVICAVITA s’appuie sur ces domaines d’expérience pour formuler ses questions de recherche et de conseil.\n\nNos textes publics privilégient les questions utiles, les preuves claires et les limites pratiques, plutôt que des promesses de transformation.','Systèmes de santé','CIVICAVITA AB','Équipe éditoriale','2026-07-15','🏥','/images/insight-health-systems.jpg',2,'["Systèmes de santé","Résilience","Politiques"]','fr','health-systems'),
('fr-editorial-responsible-ai','L’IA responsable commence par un jugement humain responsable','L’IA peut aider la recherche et la communication, mais ne peut remplacer la connaissance du contexte, l’examen éthique ou la responsabilité.','L’IA peut aider à organiser l’information, produire des premiers brouillons structurés et soutenir les flux de connaissances. En santé publique et dans les contextes humanitaires, une réponse fluide n’est toutefois pas nécessairement fiable.\n\nCIVICAVITA considère l’IA comme une technologie d’assistance. Les sources doivent être vérifiées, les incertitudes doivent être explicitées et les personnes disposant d’une connaissance pertinente du contexte restent responsables des décisions. Cela est particulièrement important lorsque les données sont incomplètes, que les situations changent rapidement ou que les conséquences d’une erreur sont graves.\n\nCIVICAVITA explore les méthodes d’IA responsable avec rigueur et ne publie que des travaux bénéficiant d’un examen humain approprié.','IA responsable','CIVICAVITA AB','Équipe éditoriale','2026-07-12','🧠','/images/insight-responsible-ai.jpg',2,'["IA responsable","Éthique","Recherche"]','fr','responsible-ai'),
('ar-editorial-evidence-field','من الخبرة المهنية إلى الدليل العام: بداية دقيقة','تبدأ سيفيكافيتا عملها العام بالفصل الواضح بين الخبرة المهنية الموثقة والادعاءات المتعلقة بالمنظمة.','تعمل سيفيكافيتا AB على تطوير نشاطها العام في البحث والاستشارات من السويد. ولا تنطلق من ادعاء تنفيذ برامج واسعة النطاق، بل من التزام باستخدام الأدلة بعناية وتحديد نطاق العمل بوضوح وتطوير النشاط تدريجيًا.\n\nتمتلك الدكتورة سحر مطلبی خبرة مهنية موثقة في الصحة العامة والسياقات الإنسانية، بما في ذلك أدوار لدى وزارات ومنظمة الصحة العالمية واليونيسف وبرنامج الأمم المتحدة الإنمائي وهيئة الأمم المتحدة للمرأة. هذه الخبرات تشكل منظور المؤسسة، لكنها لا تعني أن تلك الجهات شركاء حاليون لسيفيكافيتا.\n\nهذا الفرق مهم. ففي الصحة العالمية تعتمد المصداقية على الإسناد الشفاف والأدلة الملائمة واحترام الأشخاص والمؤسسات الأقرب إلى كل قضية.','تحريرية','CIVICAVITA AB','الفريق التحريري','2026-07-21','🔎','/images/insight-evidence-health.jpg',2,'["الأدلة","الشفافية","الصحة العالمية"]','ar','evidence-field'),
('ar-editorial-displacement-health','النزوح والمأوى والصحة: أسئلة تحتاج إلى اهتمام طويل الأمد','تأملات مستندة إلى عمل موثق حول المحددات الاجتماعية لصحة النازحين والمأوى بعد الكوارث.','المأوى المؤقت ليس مسألة لوجستية فقط. فهو يؤثر في الخصوصية والأمان والتعرض للطقس واستمرارية الرعاية والظروف الاجتماعية التي تشكل الصحة.\n\nيتضمن السجل الأكاديمي والمهني الموثق للدكتورة سحر مطلبی عملًا حول المحددات الاجتماعية لصحة السكان النازحين وعرضًا علميًا عام 2006 عن المأوى شبه الدائم بعد الكوارث. وتطرح هذه الخبرات سؤالًا مستمرًا: ماذا يحدث عندما تتحول الاستجابة القصيرة الأجل إلى ظرف معيشة طويل الأجل؟\n\nستستكشف سيفيكافيتا هذا الموضوع عبر مراجعة دقيقة للأدلة وملاحظات عامة، دون تقديم الأعمال السابقة بوصفها برنامجًا حاليًا.','العلوم الإنسانية','CIVICAVITA AB','الفريق التحريري','2026-07-18','⛺','/images/insight-humanitarian-research.jpg',2,'["النزوح","المأوى","الإنصاف الصحي"]','ar','displacement-health'),
('ar-editorial-health-systems','تُبنى النظم الصحية القادرة على الصمود بالاستمرارية والتعلم والثقة','مرونة النظام الصحي ليست ادعاءً تقنيًا؛ بل عمل مستمر على المؤسسات والبيانات والناس والوصول إلى الرعاية.','تواجه النظم الصحية ضغوطًا متزامنة مثل الأمراض المزمنة ومخاطر المناخ والنزوح ونقص القوى العاملة وعدم المساواة في الوصول إلى المعلومات. والقدرة على الصمود ليست منتجًا يُركب، بل قدرة تُبنى من خلال استمرارية الرعاية والمعرفة المحلية والتعلم والمؤسسات المسؤولة.\n\nيشمل سجل المؤسسة الموثق عملًا تقنيًا يتعلق بسياسات الأمراض غير السارية والرصد والتقييم والتخطيط للكوارث والبرامج الصحية. وتستفيد سيفيكافيتا من هذه المجالات لصياغة أسئلة البحث والاستشارة.\n\nتركز كتاباتنا العامة على الأسئلة المفيدة والأدلة الواضحة والحدود العملية، لا على وعود التحول.','النظم الصحية','CIVICAVITA AB','الفريق التحريري','2026-07-15','🏥','/images/insight-health-systems.jpg',2,'["النظم الصحية","القدرة على الصمود","السياسات"]','ar','health-systems'),
('ar-editorial-responsible-ai','يبدأ الذكاء الاصطناعي المسؤول بحكم بشري قابل للمساءلة','يمكن للذكاء الاصطناعي أن يدعم البحث والتواصل، لكنه لا يحل محل معرفة السياق أو المراجعة الأخلاقية أو المسؤولية.','يمكن للذكاء الاصطناعي أن يساعد في تنظيم المعلومات وإنشاء مسودات أولية منظمة ودعم تدفقات المعرفة. لكن في الصحة العامة والسياقات الإنسانية، لا تعني الإجابة السلسة بالضرورة أنها إجابة موثوقة.\n\nتتعامل سيفيكافيتا مع الذكاء الاصطناعي بوصفه تقنية مساندة. ويجب التحقق من المصادر وبيان عدم اليقين، ويظل الأشخاص ذوو المعرفة السياقية ذات الصلة مسؤولين عن القرارات. ويكتسب ذلك أهمية خاصة عندما تكون البيانات ناقصة أو تتغير الظروف بسرعة أو تكون عواقب الخطأ جسيمة.\n\nتستكشف سيفيكافيتا أساليب الذكاء الاصطناعي المسؤول بعناية ولا تنشر إلا الأعمال التي خضعت لمراجعة بشرية مناسبة.','الذكاء الاصطناعي المسؤول','CIVICAVITA AB','الفريق التحريري','2026-07-12','🧠','/images/insight-responsible-ai.jpg',2,'["الذكاء الاصطناعي المسؤول","الأخلاقيات","البحث"]','ar','responsible-ai');
